import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { getAlbums, deleteAlbum } from '../api/albumService';
import { getArtistes } from '../api/artisteService';
import { getChansons } from '../api/chansonService';

export default function AlbumsList() {
  const [albums, setAlbums] = useState([]);
  const [artistes, setArtistes] = useState([]);
  const [songs, setSongs] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchData = () => {
    setLoading(true);
    Promise.all([getAlbums(), getArtistes(), getChansons()])
      .then(([albumsRes, artistesRes, chansonsRes]) => {
        setAlbums(albumsRes.data || []);
        setArtistes(artistesRes.data || []);
        setSongs(chansonsRes.data || []);
      })
      .catch(() => {
        setAlbums([]);
        setArtistes([]);
        setSongs([]);
      })
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    fetchData();
  }, []);

  const findArtisteName = (artisteId) => {
    const artiste = artistes.find((item) => item.id === artisteId);
    return artiste ? artiste.nom : `Artiste ${artisteId}`;
  };

  const handleDelete = (id) => {
    if (!window.confirm('Supprimer cet album ?')) return;
    deleteAlbum(id).then(() => fetchData());
  };

  return (
    <div>
      <div className="d-flex align-items-center justify-content-between mb-4">
        <div>
          <h1 className="h3 mb-0">Albums</h1>
          <p className="text-muted mb-0">Explorez les albums et leurs artistes associés.</p>
        </div>
        <Link className="btn btn-primary" to="/albums/create">
          Créer un album
        </Link>
      </div>

      {loading ? (
        <div className="alert alert-secondary">Chargement des albums...</div>
      ) : albums.length === 0 ? (
        <div className="alert alert-warning">Aucun album disponible.</div>
      ) : (
        <div className="table-responsive">
          <table className="table table-hover align-middle">
            <thead className="table-light">
              <tr>
                <th>Album</th>
                <th>Artiste</th>
                <th>Chansons</th>
                <th>Image</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {albums.map((album) => {
                const chansonCount = songs.filter((song) => song.albumId === album.id).length;
                return (
                  <tr key={album.id}>
                    <td>
                      <Link to={`/albums/${album.id}`} className="fw-bold">
                        {album.titre || `Album ${album.id}`}
                      </Link>
                      <div className="text-muted small">ID: {album.id}</div>
                    </td>
                    <td>{findArtisteName(album.artisteId)}</td>
                    <td>{chansonCount}</td>
                    <td>
                      {album.image ? (
                        <img
                          src={`/uploads/images/${album.image}`}
                          alt={album.titre}
                          className="img-thumbnail"
                          style={{ maxWidth: 80, maxHeight: 80 }}
                        />
                      ) : (
                        <span className="text-muted">Aucune image</span>
                      )}
                    </td>
                    <td>
                      <Link className="btn btn-sm btn-outline-secondary me-2" to={`/albums/${album.id}/edit`}>
                        Modifier
                      </Link>
                      <button className="btn btn-sm btn-danger" onClick={() => handleDelete(album.id)}>
                        Supprimer
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
